.public-home-shell-head,
.public-home-shell-copy,
.public-home-rail {
  display: grid;
  gap: var(--space-4);
}

.public-home-shell-head {
  border-bottom: 1px solid var(--line);
  gap: var(--space-3);
  padding-bottom: var(--space-4);
}

.public-home-shell-copy {
  gap: var(--space-2);
}

.public-home-count {
  align-items: start;
  background: rgba(248, 250, 252, 0.92);
  border: 1px solid rgba(148, 163, 184, 0.2);
  border-radius: var(--radius-3);
  display: inline-grid;
  gap: 0.18rem;
  justify-self: start;
  min-width: 11rem;
  padding: 0.9rem 1rem;
}

.public-home-count span {
  color: var(--ink-faint);
  font-family: var(--font-ui);
  font-size: var(--text-xs);
  font-weight: 700;

:root {
  color-scheme: light;
  --bg: #eef3f7;
  --bg-strong: rgba(255, 255, 255, 0.92);
  --surface: rgba(255, 255, 255, 0.76);
  --surface-strong: rgba(255, 255, 255, 0.9);
  --surface-muted: rgba(241, 245, 249, 0.92);
  --ink: #111827;
  --ink-soft: #334155;
  --ink-muted: #64748b;
  --ink-faint: #94a3b8;
  --line: rgba(100, 116, 139, 0.22);
  --line-strong: rgba(51, 65, 85, 0.14);
  --accent: #324863;
  --accent-strong: #19293b;
  --accent-soft: rgba(50, 72, 99, 0.08);
  --accent-soft-strong: rgba(50, 72, 99, 0.14);
  --success-soft: rgba(22, 101, 52, 0.08);
  --success-line: rgba(22, 101, 52, 0.18);
  --danger-soft: rgba(185, 28, 28, 0.08);
  --danger-line: rgba(185, 28, 28, 0.16);
  --shadow-soft: 0 0.75rem 1.75rem rgba(15, 23, 42, 0.06);
  --shadow-panel: 0 1.35rem 3rem rgba(15, 23, 42, 0.08);
  --shadow-hero: 0 1.75rem 4rem rgba(15, 23, 42, 0.1);
  --radius-1: 0.9rem;
  --radius-2: 1.2rem;
  --radius-3: 1.55rem;
  --radius-4: 1.9rem;
  --radius-pill: 999px;
  --space-1: 0.35rem;
  --space-2: 0.55rem;
  --space-3: 0.8rem;
  --space-4: 1rem;
  --space-5: 1.25rem;
  --space-6: 1.5rem;
  --space-7: 1.85rem;
  --space-8: 2.3rem;
  --text-xs: 0.72rem;
  --text-sm: 0.82rem;
  --text-base: 0.95rem;
  --text-body: 1rem;
  --text-lg: 1.08rem;
  --text-xl: 1.28rem;
  --text-2xl: clamp(1.75rem, 3.8vw, 2.55rem);
  --text-display: clamp(1.95rem, 5vw, 3.35rem);
  --measure: 65ch;
  --container-max: 84rem;
  --font-display: "Avenir Next", "Segoe UI Variable", "Helvetica Neue", sans-serif;
  --font-body: "Avenir Next", "Segoe UI Variable", "Helvetica Neue", sans-serif;
  --font-ui: "Avenir Next", "Segoe UI Variable", "Helvetica Neue", sans-serif;
  --font-mono: "IBM Plex Mono", "SFMono-Regular", Menlo, Consolas, monospace;
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  min-height: 100%;
}

body {
  background:
    radial-gradient(circle at top left, rgba(148, 163, 184, 0.18), transparent 31rem),
    radial-gradient(circle at top right, rgba(191, 219, 254, 0.14), transparent 27rem),
    linear-gradient(180deg, #f8fafc 0%, #edf2f7 48%, #e5ebf2 100%);
  color: var(--ink);
  font-family: var(--font-body);
  font-size: var(--text-body);
  letter-spacing: -0.01em;
  text-rendering: optimizeLegibility;
}

a {
  color: inherit;
  text-decoration: none;
}

button,
input,
textarea {
  font: inherit;
}

::selection {
  background: rgba(50, 72, 99, 0.18);
}

.page-shell {
  min-height: 100vh;
  padding: var(--space-4);
}

.site-main {
  width: 100%;
}

.site-header,
.feature-layout,
.vault-shell,
.note-editor-shell {
  margin: 0 auto;
  max-width: var(--container-max);
}

.site-header {
  align-items: flex-start;
  backdrop-filter: blur(20px);
  background: rgba(255, 255, 255, 0.72);
  border: 1px solid rgba(148, 163, 184, 0.28);
  border-radius: var(--radius-4);
  box-shadow: var(--shadow-soft);
  display: flex;
  flex-direction: column;
  gap: var(--space-4);
  margin-bottom: var(--space-6);
  padding: 0.95rem 1.05rem;
}

.brand-block,
.hero-copy,
.vault-frame-copy {
  display: grid;
  gap: var(--space-2);
}

.brand {
  font-family: var(--font-ui);
  font-size: 0.92rem;
  font-weight: 700;
  letter-spacing: 0.2em;
  text-transform: uppercase;
}

.brand-caption,
.lede,
.field-note,
.auth-note,
.signin-error,
.status-note,
.note-list-item p,
.panel-card p,
.feature-card p,
.link-url,
.link-summary,
.note-generated-summary,
.note-generated-copy p,
.section-meta,
.tag-filter-count,
.vault-frame-note {
  color: var(--ink-muted);
}

.brand-caption,
.vault-frame-note,
.lede,
.field-note,
.auth-note,
.signin-error,
.status-note,
.link-url,
.link-summary,
.note-generated-summary,
.note-generated-copy p,
.note-list-item p {
  line-height: 1.65;
  margin: 0;
}

.brand-caption {
  font-size: var(--text-base);
  max-width: 36rem;
}

.site-nav,
.vault-nav,
.button-row,
.note-meta,
.ui-metadata-row,
.inline-list {
  align-items: center;
  display: flex;
  flex-wrap: wrap;
  gap: 0.7rem;
}

.site-nav a,
.vault-nav-link {
  border: 1px solid transparent;
  border-radius: var(--radius-pill);
  color: var(--ink-muted);
  font-family: var(--font-ui);
  font-size: var(--text-xs);
  font-weight: 700;
  letter-spacing: 0.12em;
  min-height: 2.8rem;
  padding: 0.72rem 1rem;
  text-transform: uppercase;
  transition:
    background-color 140ms ease,
    border-color 140ms ease,
    color 140ms ease,
    transform 140ms ease;
}

.site-nav a:hover,
.vault-nav-link:hover,
.route-tile:hover,
.note-list-link:hover,
.tag-filter-link:hover,
.primary-button:hover,
.ghost-button:hover,
.ui-button:hover {
  transform: translateY(-1px);
}

.site-nav a:hover,
.vault-nav-link:hover {
  background: rgba(255, 255, 255, 0.82);
  border-color: var(--line);
  color: var(--ink);
}

.vault-nav-link-active {
  background: var(--accent-soft);
  border-color: var(--accent-soft-strong);
  color: var(--accent-strong);
}

.feature-layout,
.note-editor-shell,
.login-layout,
.dashboard-grid,
.public-home-grid,
.link-manager-grid,
.retrieval-grid,
.route-grid,
.summary-row,
.tag-filter-list,
.detail-stack,
.note-editor-grid,
.link-form,
.link-list,
.link-list-item,
.link-list-heading,
.link-list-footer,
.tag-list,
.ui-tag-list,
.search-form,
.note-generated-panel,
.note-generated-copy,
.field-group {
  display: grid;
  gap: var(--space-4);
}

.feature-layout,
.note-editor-shell,

.note-preview-card .note-list-link {
  font-size: clamp(1.22rem, 2vw, 1.58rem);
  line-height: 1.02;
  margin-top: 0;
}

.note-preview-card-summary,
.note-preview-card-excerpt {
  margin: 0;
}

.note-preview-card-summary {
  color: var(--ink);
  font-size: 1rem;
  line-height: 1.68;
  max-width: 30ch;
}

.note-preview-card-excerpt {
  color: var(--ink-soft);
  font-size: var(--text-sm);
  line-height: 1.65;
  max-width: 32ch;
}

.note-preview-card-meta {
  border-top: 1px solid rgba(100, 116, 139, 0.18);
  margin-top: auto;
  padding-top: var(--space-4);
}

.note-preview-card-tags {
  margin-top: -0.15rem;
}

.link-url {
  font-family: var(--font-mono);
  font-size: var(--text-xs);
  overflow-wrap: anywhere;
}

.note-generated-summary {
  color: var(--ink-soft);
}

.enrichment-status-block {
  display: grid;
  gap: 0.35rem;
}

.enrichment-status-block .note-meta-leading {
  margin-bottom: 0;
}

.note-meta,
.ui-metadata-row {
  color: var(--ink-faint);
  font-size: 0.7rem;
  letter-spacing: 0.14em;
  text-transform: uppercase;
}

.note-meta-leading {
  margin-bottom: 0.2rem;
}

.link-list-footer {
  gap: var(--space-3);
}

.tag-list,
.ui-tag-list {
  align-items: start;
  grid-template-columns: repeat(auto-fit, minmax(6.5rem, max-content));
}

.tag-pill,
.ui-tag {
  align-items: center;
  background: var(--accent-soft);
  border: 1px solid var(--accent-soft-strong);
  border-radius: var(--radius-pill);
  color: var(--accent-strong);
  display: inline-flex;
  font-family: var(--font-ui);
  font-size: var(--text-xs);
  font-weight: 700;
  letter-spacing: 0.08em;
  min-height: 2.35rem;
  padding: 0.45rem 0.8rem;
  text-transform: uppercase;
}

.tag-pill-muted,
.ui-tag-muted {
  background: rgba(255, 255, 255, 0.7);
  border-color: var(--line);
  color: var(--ink-muted);
}

.tag-filter-list {
  grid-template-columns: repeat(auto-fit, minmax(12rem, 1fr));
}

.tag-filter-link {
  color: var(--ink);
  gap: 0.45rem;
  min-height: 4.5rem;
}

.tag-filter-link-active {
  background: rgba(239, 244, 249, 0.98);
  border-color: var(--accent-soft-strong);
}

.tag-filter-count {
  font-family: var(--font-body);
  font-size: var(--text-base);
  letter-spacing: normal;
  text-transform: none;
}

.route-grid {
  grid-template-columns: minmax(0, 1fr);
}

.route-tile {
  display: grid;
  gap: 0.4rem;
}

.route-tile strong {
  margin-bottom: 0;
}

.route-tile span {
  color: var(--ink-muted);
  line-height: 1.6;
}

.search-form {
  align-items: end;
}

.markdown-preview {
  border-top: 1px solid var(--line);
  color: var(--ink-soft);
  margin-top: var(--space-4);
  padding-top: var(--space-5);
}

.markdown-preview > :first-child {
  margin-top: 0;
}

.markdown-preview > :last-child {
  margin-bottom: 0;
}

.markdown-preview h1,
.markdown-preview h2,
.markdown-preview h3,
.markdown-preview h4,
.markdown-preview h5,
.markdown-preview h6 {
  color: var(--ink);
  font-family: var(--font-display);
  font-weight: 650;
  letter-spacing: -0.03em;
  line-height: 1.08;
  margin: 1.45rem 0 0.7rem;
}

.markdown-preview h1 {
  font-size: 1.85rem;
}

.markdown-preview h2 {
  font-size: 1.52rem;
}

.markdown-preview h3 {
  font-size: 1.22rem;
}

.markdown-preview p,
.markdown-preview li,
.markdown-preview blockquote {
  line-height: 1.74;
}

.markdown-preview p,
.markdown-preview ul,
.markdown-preview ol,
.markdown-preview pre,
.markdown-preview blockquote {
  margin: 0 0 0.95rem;
}

.markdown-preview ul,
.markdown-preview ol {
  padding-left: 1.3rem;
}

.markdown-preview code {
  background: rgba(15, 23, 42, 0.08);
  border-radius: 0.45rem;
  padding: 0.12rem 0.35rem;
}

.markdown-preview pre {
  background: #0f172a;
  border-radius: var(--radius-2);
  color: #f8fafc;
  overflow-x: auto;
  padding: 1rem;
}

.markdown-preview pre code {
  background: transparent;
  padding: 0;
}

.markdown-preview blockquote {
  border-left: 3px solid rgba(50, 72, 99, 0.32);
  color: var(--ink-muted);
  margin-left: 0;
  padding-left: 0.95rem;
}

.markdown-preview a {
  color: var(--accent-strong);
  text-decoration: underline;
  text-decoration-thickness: 1px;
  text-underline-offset: 0.18em;
}

.bullet-list {
  color: var(--ink-muted);
  display: grid;
  gap: 0.65rem;
  line-height: 1.65;
  margin: var(--space-5) 0 0;
  padding-left: 1.1rem;
}

.inline-list {
  list-style: none;
  margin: 0;
  padding: 0;
}

.inline-list li {
  border: 1px solid var(--line);
  border-radius: var(--radius-pill);
  color: var(--ink-muted);
  padding: 0.5rem 0.8rem;
}

@media (min-width: 640px) {
  .page-shell {
    padding: var(--space-5);
  }

  .ui-surface,
  .hero-card,
  .panel-card,
  .feature-card,
  .vault-frame {
    padding: var(--space-6);
  }
}

@media (min-width: 768px) {
  .page-shell {
    padding: var(--space-6);
  }

  .site-header {
    align-items: center;
    flex-direction: row;
    justify-content: space-between;
  }

  .summary-row {
    grid-template-columns: repeat(3, minmax(0, 1fr));
  }

  .public-home-grid,
  .dashboard-grid {
    grid-template-columns: minmax(0, 1.16fr) minmax(18rem, 0.84fr);
  }

  .public-home-shell-head {
    align-items: end;
    grid-template-columns: minmax(0, 1fr) auto;
  }

  .public-note-list {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .public-note-showroom {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .note-preview-card-balanced {
    min-height: 17rem;
  }

  .note-preview-card-feature {
    min-height: 21rem;
  }

  .login-layout {
    grid-template-columns: minmax(0, 1.02fr) minmax(18rem, 0.98fr);
  }

  .link-manager-grid {
    align-items: start;
    grid-template-columns: minmax(0, 0.92fr) minmax(0, 1.08fr);
  }

  .note-editor-grid {
    grid-template-columns: minmax(0, 1.02fr) minmax(0, 0.98fr);
  }

  .note-list-item {
    grid-template-columns: minmax(0, 1fr) auto;
  }

  .link-list-footer {
    align-items: center;
    grid-template-columns: minmax(0, 1fr) auto;
  }

  .retrieval-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .route-grid {
    grid-template-columns: repeat(3, minmax(0, 1fr));
  }
}

@media (min-width: 1024px) {
  .ui-surface,
  .hero-card,
  .panel-card,
  .feature-card,
  .vault-frame {
    padding: var(--space-7);
  }

  .vault-frame-header {
    align-items: end;
    grid-template-columns: minmax(0, 1fr) auto;
  }

  .public-note-card {
    padding: var(--space-7);
  }

  .public-home-grid {
    grid-template-columns: minmax(0, 1.36fr) minmax(18rem, 0.64fr);
  }

  .public-note-showroom {
    gap: var(--space-5);
  }

  .public-note-header-row {
    grid-template-columns: minmax(0, 1fr) auto;
  }

  .public-note-support {
    grid-template-columns: minmax(0, 1.35fr) minmax(14rem, 0.65fr);
  }
}

  font-weight: 700;
  letter-spacing: 0.16em;
  text-transform: uppercase;
}

.public-home-count strong {
  color: var(--ink);
  font-family: var(--font-display);
  font-size: clamp(1.2rem, 2vw, 1.5rem);
  font-weight: 650;
  letter-spacing: -0.03em;
  line-height: 1.05;
}

.public-intro-panel {
  gap: var(--space-3);
}

.public-intro-panel h1 {
  font-size: clamp(1.55rem, 3vw, 2.15rem);
  line-height: 1.02;
  max-width: 13ch;
}

.public-intro-panel .lede {
  font-size: var(--text-sm);
  max-width: 30rem;
}

.note-collection-panel,
.link-list-panel,
.note-preview-panel,
.public-note-card,
.login-form-card {
  background:
    linear-gradient(180deg, rgba(255, 255, 255, 0.66), transparent 20%),
    var(--surface-strong);
}

.public-note-card {
  margin: 0 auto;
  max-width: 50rem;
  padding: var(--space-6) var(--space-5);
  position: relative;
}

.public-note-header {
  display: grid;
  gap: var(--space-5);
}

.public-note-header-row,
.public-note-title-block,
.public-note-support-block {
  display: grid;
  gap: var(--space-3);
}

.public-note-header-row {
  align-items: center;
}

.public-note-title-block {
  gap: var(--space-2);
}

.public-note-header h1 {
  font-size: clamp(1.8rem, 4vw, 2.35rem);
  line-height: 0.98;
  margin: 0;
  max-width: 18ch;
}

.public-note-meta {
  gap: 0.55rem 0.8rem;
}

.public-note-back-link {
  background: transparent;
  border: none;
  box-shadow: none;
  color: var(--ink-muted);
  justify-self: start;
  min-height: auto;
  padding: 0;
}

.public-note-back-link:hover,
.public-note-back-link:focus-visible {
  color: var(--accent-strong);
}

.public-note-support {
  border-top: 1px solid var(--line);
  display: grid;
  gap: var(--space-4);
  margin-top: var(--space-6);
  padding-top: var(--space-4);
}

.public-note-lede {
  max-width: 38rem;
}

.public-note-body {
  font-size: 1.02rem;
  line-height: 1.82;
  margin-top: var(--space-5);
}

.public-note-body > * {
  max-width: min(100%, 65ch);
}

.public-note-body pre,
.public-note-body figure {
  max-width: 100%;
}

.public-note-tags {
  gap: 0.55rem;
  grid-template-columns: repeat(auto-fit, minmax(5.25rem, max-content));
}

.public-note-tag {
  background: rgba(50, 72, 99, 0.06);
  border-color: rgba(50, 72, 99, 0.12);
  color: var(--ink-muted);
  font-size: 0.66rem;
  letter-spacing: 0.12em;
  min-height: 1.9rem;
  padding: 0.3rem 0.68rem;
}

.note-editor-intro,
.note-form,
.note-preview-panel {
  min-width: 0;
}

.note-form {
  align-content: start;
}

.note-body-field {
  min-height: 0;
}

.text-input,
.note-textarea,
.sign-in-form input {
  background: rgba(248, 250, 252, 0.9);
  border: 1px solid rgba(100, 116, 139, 0.2);
  border-radius: var(--radius-2);
  color: var(--ink);
  padding: 0.92rem 1rem;
  transition:
    border-color 140ms ease,
    box-shadow 140ms ease,
    background-color 140ms ease;
  width: 100%;
}

.text-input:focus,
.note-textarea:focus,
.sign-in-form input:focus {
  background: #ffffff;
  border-color: rgba(50, 72, 99, 0.34);
  box-shadow: 0 0 0 0.2rem rgba(50, 72, 99, 0.1);
  outline: none;
}

.note-textarea {
  min-height: 25rem;
  resize: vertical;
}

.summary-textarea {
  min-height: 10rem;
}

.sign-in-form {
  display: grid;
  gap: var(--space-4);
}

.sign-in-form label {
  color: var(--ink-soft);
  display: grid;
  font-size: var(--text-sm);
  gap: 0.45rem;
  letter-spacing: 0.02em;
}

.field-group {
  gap: 0.45rem;
}

.field-group span {
  color: var(--ink-muted);
  font-size: var(--text-xs);
  letter-spacing: 0.1em;
  text-transform: uppercase;
}

.button-row {
  gap: 0.75rem;
  margin-top: 0.25rem;
}

.primary-button,
.ghost-button,
.ui-button {
  align-items: center;
  border-radius: var(--radius-pill);
  cursor: pointer;
  display: inline-flex;
  font-size: var(--text-xs);
  font-weight: 700;
  justify-content: center;
  letter-spacing: 0.12em;
  min-height: 2.8rem;
  padding: 0.72rem 1.1rem;
  text-transform: uppercase;
  transition:
    transform 140ms ease,
    background-color 140ms ease,
    border-color 140ms ease,
    color 140ms ease,
    box-shadow 140ms ease;
}

.primary-button,
.ui-button-primary {
  background: linear-gradient(180deg, #415a77 0%, var(--accent-strong) 100%);
  border: 1px solid rgba(25, 41, 59, 0.24);
  box-shadow: 0 0.85rem 1.5rem rgba(25, 41, 59, 0.18);
  color: #f8fafc;
}

.ghost-button,
.ui-button-ghost {
  background: rgba(255, 255, 255, 0.8);
  border: 1px solid var(--line);
  color: var(--ink);
}

.primary-button:focus-visible,
.ghost-button:focus-visible,
.ui-button:focus-visible,
.site-nav a:focus-visible,
.vault-nav-link:focus-visible,
.note-list-link:focus-visible,
.tag-filter-link:focus-visible {
  outline: 2px solid rgba(50, 72, 99, 0.28);
  outline-offset: 3px;
}

.status-note {
  background: var(--success-soft);
  border: 1px solid var(--success-line);
  border-radius: var(--radius-2);
  margin-top: var(--space-4);
  padding: 0.9rem 1rem;
}

.status-note-error,
.signin-error {
