  color: var(--accent);
  font-family: var(--font-ui);
  font-size: var(--text-xs);
  font-weight: 700;
  letter-spacing: 0.22em;
  margin: 0;
  text-transform: uppercase;
}

.summary-row {
  border-top: 1px solid var(--line);
  margin-top: var(--space-6);
  padding-top: var(--space-5);
}

.summary-row strong,
.section-heading strong,
.ui-section-heading strong,
.note-generated-copy strong,
.panel-card strong {
  display: block;
  font-size: var(--text-xs);
  font-weight: 700;
  letter-spacing: 0.16em;
  margin-bottom: 0.3rem;
  text-transform: uppercase;
}

.summary-row span,
.section-meta {
  display: block;
}

.section-heading,
.ui-section-heading {
  align-items: baseline;
  border-bottom: 1px solid var(--line);
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem 0.75rem;
  justify-content: space-between;
  margin-bottom: 0.15rem;
  padding-bottom: var(--space-4);
}

.section-meta {
  font-family: var(--font-ui);
  font-size: var(--text-xs);
  letter-spacing: 0.1em;
  text-transform: uppercase;
}

.detail-stack {
  margin-top: var(--space-4);
}

.vault-shell {
  width: 100%;
}

.vault-frame {
  box-shadow: var(--shadow-soft);
  display: grid;
  gap: 0;
  padding: var(--space-4);
}

.vault-shell-grid {
  align-items: start;
  display: grid;
  gap: var(--space-5);
  min-width: 0;
}

.vault-frame-header {
  border-bottom: 1px solid var(--line);
  display: grid;
  gap: var(--space-4);
  padding-bottom: var(--space-4);
}

.vault-nav-block {
  gap: var(--space-3);
}

.vault-nav-label {
  color: var(--ink-faint);
  font-family: var(--font-ui);
  font-size: 0.68rem;
  font-weight: 700;
  letter-spacing: 0.16em;
  margin: 0;
  text-transform: uppercase;
}

.vault-nav {
  gap: 0.55rem;
}

.vault-frame-body {
  display: grid;
  gap: var(--space-5);
  min-width: 0;
}

.vault-frame-body > * {
  min-width: 0;
}

.public-home-layout,
.public-note-layout,
.login-layout {
  align-items: start;
}

.public-home-layout {
  gap: var(--space-5);
}

.public-note-layout {
  gap: var(--space-4);
}

.public-side-panel,
.dashboard-side-panel,
.login-form-card {
  align-self: start;
}

.public-hero,
.note-editor-intro {
  overflow: hidden;

    grid-template-columns: minmax(14.5rem, 16rem) minmax(0, 1fr);
  }

  .vault-frame-header {
    align-content: start;
    border-bottom: none;
    border-right: 1px solid var(--line);
    padding-bottom: 0;
    padding-right: var(--space-5);
  }

  .vault-nav {
    align-items: stretch;
    flex-direction: column;
  }

  .vault-nav-link {
    justify-content: flex-start;
    width: 100%;
  }

  .public-note-card {
    padding: var(--space-7);
  }

  .public-home-grid {
    grid-template-columns: minmax(0, 1.36fr) minmax(18rem, 0.64fr);
  }

  .public-note-showroom {
    gap: var(--space-5);
  }

  .public-note-header-row {
    grid-template-columns: minmax(0, 1fr) auto;
  }

  .public-note-support {
    grid-template-columns: minmax(0, 1.35fr) minmax(14rem, 0.65fr);
  }
}
